265	// GenerateResponseFunc is a function that [Client.Generate] invokes every time
266	// a response is received from the service. If this function returns an error,
267	// [Client.Generate] will stop generating and return this error.
268	type GenerateResponseFunc func(GenerateResponse) error
269	
270	// Generate generates a response for a given prompt. The req parameter should
271	// be populated with prompt details. fn is called for each response (there may
272	// be multiple responses, e.g. in case streaming is enabled).
273	func (c *Client) Generate(ctx context.Context, req *GenerateRequest, fn GenerateResponseFunc) error {
274		return c.stream(ctx, http.MethodPost, "/api/generate", req, func(bts []byte) error {
275			var resp GenerateResponse
276			if err := json.Unmarshal(bts, &resp); err != nil {
277				return err
278			}
279	
280			return fn(resp)
281		})
282	}
283	
284	// ChatResponseFunc is a function that [Client.Chat] invokes every time
285	// a response is received from the service. If this function returns an error,
286	// [Client.Chat] will stop generating and return this error.
287	type ChatResponseFunc func(ChatResponse) error
288	
289	// Chat generates the next message in a chat. [ChatRequest] may contain a
290	// sequence of messages which can be used to maintain chat history with a model.
291	// fn is called for each response (there may be multiple responses, e.g. if case
292	// streaming is enabled).
293	func (c *Client) Chat(ctx context.Context, req *ChatRequest, fn ChatResponseFunc) error {
294		return c.stream(ctx, http.MethodPost, "/api/chat", req, func(bts []byte) error {
295			var resp ChatResponse
296			if err := json.Unmarshal(bts, &resp); err != nil {
297				return err
298			}
299	
300			return fn(resp)
301		})
302	}
303	
304	// PullProgressFunc is a function that [Client.Pull] invokes every time there
305	// is progress with a "pull" request sent to the service. If this function
306	// returns an error, [Client.Pull] will stop the process and return this error.
307	type PullProgressFunc func(ProgressResponse) error
308	
309	// Pull downloads a model from the ollama library. fn is called each time
310	// progress is made on the request and can be used to display a progress bar,
311	// etc.
312	func (c *Client) Pull(ctx context.Context, req *PullRequest, fn PullProgressFunc) error {
313		return c.stream(ctx, http.MethodPost, "/api/pull", req, func(bts []byte) error {
314			var resp ProgressResponse
315			if err := json.Unmarshal(bts, &resp); err != nil {
316				return err
317			}
318	
319			return fn(resp)
320		})
321	}
322	
323	// PushProgressFunc is a function that [Client.Push] invokes when progress is
324	// made.
325	// It's similar to other progress function types like [PullProgressFunc].
326	type PushProgressFunc func(ProgressResponse) error
327	
328	// Push uploads a model to the model library; requires registering for ollama.ai
329	// and adding a public key first. fn is called each time progress is made on
330	// the request and can be used to display a progress bar, etc.
331	func (c *Client) Push(ctx context.Context, req *PushRequest, fn PushProgressFunc) error {
332		return c.stream(ctx, http.MethodPost, "/api/push", req, func(bts []byte) error {
333			var resp ProgressResponse
334			if err := json.Unmarshal(bts, &resp); err != nil {
335				return err
336			}
337	
338			return fn(resp)
339		})
340	}
341	
342	// CreateProgressFunc is a function that [Client.Create] invokes when progress
343	// is made.
344	// It's similar to other progress function types like [PullProgressFunc].
345	type CreateProgressFunc func(ProgressResponse) error
346	
347	// Create creates a model from a [Modelfile]. fn is a progress function that
348	// behaves similarly to other methods (see [Client.Pull]).
349	//
350	// [Modelfile]: https://github.com/ollama/ollama/blob/main/docs/modelfile.mdx
351	func (c *Client) Create(ctx context.Context, req *CreateRequest, fn CreateProgressFunc) error {
352		return c.stream(ctx, http.MethodPost, "/api/create", req, func(bts []byte) error {
353			var resp ProgressResponse
354			if err := json.Unmarshal(bts, &resp); err != nil {
355				return err
356			}
357	
358			return fn(resp)
359		})
360	}
361	
362	// List lists models that are available locally.
363	func (c *Client) List(ctx context.Context) (*ListResponse, error) {
364		var lr ListResponse
365		if err := c.do(ctx, http.MethodGet, "/api/tags", nil, &lr); err != nil {
366			return nil, err
367		}
368		return &lr, nil
369	}
370	
371	// ListRunning lists running models.
372	func (c *Client) ListRunning(ctx context.Context) (*ProcessResponse, error) {
373		var lr ProcessResponse
374		if err := c.do(ctx, http.MethodGet, "/api/ps", nil, &lr); err != nil {
