1497		termWidth, _, _ := term.GetSize(int(os.Stdout.Fd()))
1498		if termWidth == 0 {
1499			termWidth = 80
1500		}
1501		if wordWrap && termWidth >= 10 {
1502			for _, ch := range content {
1503				if state.lineLength+1 > termWidth-5 {
1504					if runewidth.StringWidth(state.wordBuffer) > termWidth-10 {
1505						fmt.Printf("%s%c", state.wordBuffer, ch)
1506						state.wordBuffer = ""
1507						state.lineLength = 0
1508						continue
1509					}
1510	
1511					// backtrack the length of the last word and clear to the end of the line
1512					a := runewidth.StringWidth(state.wordBuffer)
1513					if a > 0 {
1514						fmt.Printf("\x1b[%dD", a)
1515					}
1516					fmt.Printf("\x1b[K\n")
1517					fmt.Printf("%s%c", state.wordBuffer, ch)
1518					chWidth := runewidth.RuneWidth(ch)
1519	
1520					state.lineLength = runewidth.StringWidth(state.wordBuffer) + chWidth
1521				} else {
1522					fmt.Print(string(ch))
1523					state.lineLength += runewidth.RuneWidth(ch)
1524					if runewidth.RuneWidth(ch) >= 2 {
1525						state.wordBuffer = ""
1526						continue
1527					}
1528	
1529					switch ch {
1530					case ' ', '\t':
1531						state.wordBuffer = ""
1532					case '\n', '\r':
1533						state.lineLength = 0
1534						state.wordBuffer = ""
1535					default:
1536						state.wordBuffer += string(ch)
1537					}
1538				}
1539			}
1540		} else {
1541			fmt.Printf("%s%s", state.wordBuffer, content)
1542			if len(state.wordBuffer) > 0 {
1543				state.wordBuffer = ""
1544			}
1545		}
