func CopyModel(src, dst model.Name) error {
    // Validate fully qualified names
    if !dst.IsFullyQualified() {
        return model.Unqualified(dst)
    }
    if !src.IsFullyQualified() {
        return model.Unqualified(src)
    }

    // Avoid no-op
    if src.Filepath() == dst.Filepath() {
        return nil
    }

    // Get manifest directory
    manifests, err := manifest.Path()
    if err != nil {
        return err
    }

    // Create destination directory and file
    dstpath := filepath.Join(manifests, dst.Filepath())
    if err := os.MkdirAll(filepath.Dir(dstpath), 0o755); err != nil {
        return err
    }

    // Copy source to destination
    srcpath := filepath.Join(manifests, src.Filepath())
    srcfile, err := os.Open(srcpath)
    if err != nil {
        return err
    }
    defer srcfile.Close()

    dstfile, err := os.Create(dstpath)
    if err != nil {
        return err
    }
    defer dstfile.Close()

    _, err = io.Copy(dstfile, srcfile)
    return err
}
```

**Key implementation details:**
- Uses `model.Name.Filepath()` to get the filesystem path
- Requires names to be fully qualified (host, namespace, model, tag)
- Uses `manifest.Path()` to get the models directory
- Performs simple file copying for the manifest

